  @Test
  public void testResourceToString_readsContentFromTempZip() throws Exception {
    // We create a subclass with a public static method that calls resourceToString with overridden getResourceFile.

    class ParseBenchmarkWithOverride extends ParseBenchmark {
      private static File getResourceFile(String path) {
        return tempZipFile;
      }

      private static String resourceToStringOverride(String fileName) throws Exception {
        ZipFile zipFile = new ZipFile(getResourceFile("/ParseBenchmarkData.zip"));
        try {
          ZipEntry zipEntry = zipFile.getEntry(fileName);
          if (zipEntry == null) {
            throw new IOException("Entry not found: " + fileName);
          }
          Reader reader = new InputStreamReader(zipFile.getInputStream(zipEntry));
          char[] buffer = new char[8192];
          StringWriter writer = new StringWriter();
          int count;
          while ((count = reader.read(buffer)) != -1) {
            writer.write(buffer, 0, count);
          }
          reader.close();
          return writer.toString();

        } finally {
          zipFile.close();
        }
      }
    }

    String content = ParseBenchmarkWithOverride.resourceToStringOverride("testfile.txt");
    assertEquals("Hello, world!", content);
  }
